import React from 'react';
import './Portfolio.css'
import project1Img from '../images/c#.png';
import project2Img from '../images/excel.png';
import project3Img from '../images/figma.png';
import project4Img from '../images/Python.png';
import project5Img from '../images/webdev.png';
import project6Img from '../images/workflow.png';


const Projects = () => {
  const projects = [
    { title: 'Project One', image: project1Img, description: 'First custom project image.', links: '| DEMO | MORE |' },
    { title: 'Project Two', image: project2Img, description: 'Second custom project image.', links: '| DEMO | MORE |' },
    { title: 'Project Three', image: project3Img, description: 'Third custom project image.', links: '| DEMO | MORE |' },
    { title: 'Project Four', image: project4Img, description: 'Fourth custom project image.', links: '| DEMO | MORE |' },
    { title: 'Project Five', image: project5Img, description: 'Fifth custom project image.', links: '| DEMO | MORE |' },
    { title: 'Project Six', image: project6Img, description: 'Sixth custom project image.', links: '| DEMO | MORE |' }
  ];

  return (
    <section id="portfolio" className="portfolio-section">
      <div className="mountains-hero">
        <div className="section-header-box">PROJECTS</div>
      </div>

      <div className="portfolio-filter-bar">
            <span className="active">Throughout my journey as a developer, I've had the opportunity to work on a variety of projects that have challenged me and helped me grow. <br style={{letterSpacing: '0.03em'}}/>Here are some of my recent works:</span>
            
      </div>
      

       <div className="portfolio-grid">
        {projects.map((project, index) => {
          return (
            <div key={index} className="portfolio-item circle-tile">
              <div className="circle-container">
                <img src={project.image} alt={project.title} className="portfolio-img-fill" />
                <div className="portfolio-overlay">
                  <h5>{project.title}</h5>
                  <p className="overlay-description">{project.description}</p>
                  <div className="overlay-links">{project.links}</div>
                </div>
              </div>
            </div>
          );
        })}
      </div> 

    

      <div className="grid-footer">And many more to come!</div>
    </section>
  );
};

export default Projects;
